// ── STEP 1: Extract & clean all Webflow form fields ──────────────────
const body = $input.item.json.body || $input.item.json;

// Handle various Webflow field name formats
const firstName  = (body.first_name  || body.firstName  || body['first-name']  || '').trim();
const lastName   = (body.last_name   || body.lastName   || body['last-name']   || '').trim();
const email      = (body.work_email  || body.email      || body['work-email']  || '').trim().toLowerCase();
const company    = (body.company     || '').trim();
const role       = (body.role        || '').trim();
const challenge  = (body.challenge   || body.marketing_challenge || body['what-s-your-biggest-marketing-challenge-right-now-'] || body['marketing-challenge'] || '').trim();
const consentRaw = body.consent || body.gdpr_consent || body['i-agree-that-candid-may-contact-me-regarding-this-request'] || false;
const consent    = consentRaw === true || consentRaw === 'true' || consentRaw === '1' || consentRaw === 'on';

// Validate required fields
if (!email)   throw new Error('MISSING_FIELD: work_email is required');
if (!firstName) throw new Error('MISSING_FIELD: first_name is required');
if (!company) throw new Error('MISSING_FIELD: company is required');

// Extract domain for Apollo enrichment
const emailDomain = email.includes('@') ? email.split('@')[1] : '';

return {
  firstName,
  lastName,
  fullName:    `${firstName} ${lastName}`.trim(),
  email,
  emailDomain,
  company,
  role,
  challenge,
  consent,
  submittedAt: new Date().toISOString()
};

// ── STEP 3: Extract useful fields from Apollo response ────────────────
const response = $input.item.json;
const org = response.organization || {};
const formData = $('Prepare Lead Data').item.json;

// Gracefully handle missing data
return {
  // Pass through all form data
  ...formData,

  // Apollo enrichment fields
  apollo_employees:    org.estimated_num_employees || 'Unknown',
  apollo_industry:     org.industry                || 'Unknown',
  apollo_country:      org.country                 || 'Unknown',
  apollo_revenue:      org.annual_revenue_printed   || 'Unknown',
  apollo_linkedin:     org.linkedin_url             || '',
  apollo_description:  (org.short_description       || '').slice(0, 400),
  apollo_founded:      org.founded_year             || '',
  apollo_technologies: (org.technology_names        || []).slice(0, 8).join(', '),
  apollo_name:         org.name                     || formData.company,
  apollo_website:      org.website_url              || '',
  apollo_success:      !!org.name
};

// ── STEP 4: Parse Google News RSS into readable bullet points ─────────
const prevData = $('Parse Apollo Data').item.json;
const response = $input.item.json;

let newsText = '';
try {
  newsText = typeof response.data === 'string' ? response.data
           : typeof response      === 'string' ? response
           : '';

  // Extract titles — handles CDATA and plain XML
  const titleRx = /<title>(?:<!\[CDATA\[)?(.*?)(?:\]\]>)?<\/title>/g;
  const dateRx  = /<pubDate>(.*?)<\/pubDate>/g;

  const titles = [];
  const dates  = [];
  let m;
  while ((m = titleRx.exec(newsText)) !== null) titles.push(m[1].trim());
  while ((m = dateRx.exec(newsText))  !== null) dates.push(m[1].trim());

  // Skip index 0 (feed title), take next 5
  const items = titles.slice(1, 6).map((title, i) => {
    const date = dates[i] ? ' (' + dates[i].slice(0, 16) + ')' : '';
    return `• ${title.replace(/&amp;/g,'&').replace(/&lt;/g,'<').replace(/&gt;/g,'>')}${date}`;
  });

  return {
    ...prevData,
    news_summary: items.length ? items.join('\n') : 'No recent news found in the last 90 days.',
    news_count:   Math.max(0, items.length)
  };
} catch(e) {
  return {
    ...prevData,
    news_summary: 'News search unavailable.',
    news_count: 0
  };
}

// ── STEP 5: Build prompts for Gemini — scoring + brief ───────────────
const d = $input.item.json;

// ─── SCORING PROMPT ───────────────────────────────────────────────────
const scoringPrompt = `You are a lead scoring expert for Candid Platform, an AI-powered Live Marketing infrastructure company based in Amsterdam (Netherlands) and London (UK).

CANDID'S IDEAL CUSTOMER PROFILE:
- Company size: 200–10,000 employees (ideal), 50–200 (acceptable), under 50 (poor fit)
- Core industries: Consumer & Retail, Financial Services, Food & Beverage, Automotive, Transportation, Manufacturing, Healthcare, Media & Communications
- Geography: Netherlands and UK (ideal), broader EU (good), rest of world (lower priority)
- Contact roles: CMO/Head of Marketing = 10, CEO/Founder = 9, Marketing Director = 8, Marketing Manager = 5, Brand/Comms Manager = 6, Other = 2
- Pain points they solve: fragmented AI tools, slow campaign cycles, quarterly planning lag, briefing bottlenecks, managing too many agencies
- Reference clients for comparison: Rabobank, AkzoNobel, Danone, Nintendo, Schiphol Airport, Albert Heijn, Alpine, ProRail

LEAD DATA:
- Full name: ${d.fullName}
- Role: ${d.role}
- Company: ${d.company}
- Email domain: ${d.emailDomain}
- Marketing challenge stated: "${d.challenge}"
- Company size (Apollo): ${d.apollo_employees} employees
- Industry (Apollo): ${d.apollo_industry}
- Country (Apollo): ${d.apollo_country}
- Annual revenue (Apollo): ${d.apollo_revenue}
- Company description: ${d.apollo_description}
- Technologies used: ${d.apollo_technologies}
- Recent company news:\n${d.news_summary}

SCORING DIMENSIONS — score each with specific evidence from the data above:
1. Contact Seniority (weight 25%): CMO/Head of Mktg/CEO/Founder=10, Marketing Director=8, Brand/Comms Mgr=6, Marketing Manager=5, Growth/Performance=4, Other=2
2. Company Size (weight 20%): 200–10000 employees=10, 50–200=6, under 50=2, over 10000=7
3. Industry Match (weight 20%): Core industries above=10, Adjacent industries=6, Other=3
4. Geography (weight 15%): Netherlands or UK=10, EU=6, rest of world=3
5. Buying Signals (weight 15%): Recent funding/growth/AI initiative/digital transformation news=10, some signals=5, no signals=3
6. Red Flag Check (weight 5%): No issues=10, minor concerns=5, is a competitor/student/freelancer/no budget=1

CHALLENGE KEYWORD BONUS: If their challenge mentions AI tools, campaign speed, fragmented workflows, briefing bottlenecks, content production, or agency management — add 0.5 bonus points to the final score.

CALCULATION: weighted_total = (seniority×0.25) + (size×0.20) + (industry×0.20) + (geography×0.15) + (signals×0.15) + (flags×0.05) + challenge_bonus. Cap at 10.
TIER: 8–10 = Hot, 5–7.9 = Warm, below 5 = Cold

RETURN ONLY VALID JSON — no markdown, no text outside the JSON:
{"score_seniority":0,"score_size":0,"score_industry":0,"score_geography":0,"score_signals":0,"score_flags":0,"challenge_bonus":0,"weighted_total":0,"tier":"Warm","evidence":"...","product_recommendation":"...","product_reasoning":"...","opening_line":"...","key_objections":"..."}`;

// ─── BRIEF PROMPT ────────────────────────────────────────────────────
const briefPrompt = `You are a senior sales consultant at Candid Platform writing a pre-call brief for a strategy session.

ABOUT CANDID: AI-powered Live Marketing infrastructure for enterprise brands. Products: Gateway (central AI workspace), Cortex (automated workflows + digital employees), Studio (AI creative production), mJourney (location signals), RLVNT (real-time media buying), GENRTR (DTC commerce engine). Clients: Rabobank, Nintendo, AkzoNobel, Danone, Schiphol.

LEAD:
Name: ${d.fullName} | Role: ${d.role} | Company: ${d.company}
Email: ${d.email} | Submitted: ${d.submittedAt}
Marketing Challenge: "${d.challenge}"
Company: ${d.apollo_employees} employees | ${d.apollo_industry} | ${d.apollo_country}
Description: ${d.apollo_description}
Technologies: ${d.apollo_technologies}
Recent news:\n${d.news_summary}

Write a sharp pre-call brief under 450 words with these exact sections:

## WHO THIS IS
2 sentences: who this person is and their decision-making influence.

## THEIR COMPANY
3 sentences: what they do, scale, why Live Marketing is relevant for them specifically.

## RECENT NEWS
Up to 3 bullet points of most relevant recent developments with brief commentary on what each means for the call.

## WHY THEY APPLIED
Your interpretation connecting their stated challenge to Candid's value proposition. Be specific.

## RECOMMENDED PRODUCT
One sentence: which Candid product fits best and exactly why.

## CALL OPENING LINE
One word-for-word sentence to open the call with — reference their specific challenge.

## PREPARE FOR THESE OBJECTIONS
2–3 likely objections with a brief counter-argument for each.

Write in Candid's voice: direct, confident, smart. No fluff, no buzzwords, no filler sentences.`;

return {
  ...d,
  scoringPrompt,
  briefPrompt
};

// ── STEP 6: Parse Gemini scoring response ────────────────────────────
const geminiResponse = $input.item.json;
const context = $('Build AI Context').item.json;
let scoreData;

try {
  const text = geminiResponse.choices[0].message.content;
  // Strip markdown code fences if Gemini adds them
  const clean = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  // Extract JSON object from response
  const jsonMatch = clean.match(/\{[\s\S]*\}/);
  if (!jsonMatch) throw new Error('No JSON object found in response');
  scoreData = JSON.parse(jsonMatch[0]);

  // Re-validate tier based on actual score (safety check)
  const score = parseFloat(scoreData.weighted_total) || 5;
  const cappedScore = Math.min(10, Math.max(1, score));
  scoreData.weighted_total = Math.round(cappedScore * 10) / 10;
  if (cappedScore >= 8)     scoreData.tier = 'Hot';
  else if (cappedScore >= 5) scoreData.tier = 'Warm';
  else                       scoreData.tier = 'Cold';

} catch(e) {
  scoreData = {
    score_seniority: 5,
    score_size: 5,
    score_industry: 5,
    score_geography: 5,
    score_signals: 5,
    score_flags: 10,
    challenge_bonus: 0,
    weighted_total: 5,
    tier: 'Warm',
    evidence: 'AI scoring unavailable - manual review required. Error: ' + e.message,
    product_recommendation: 'Full Live Marketing Partnership',
    product_reasoning: 'Default - pending manual review.',
    opening_line: "Thank you for your interest in Candid - I would love to learn more about your current marketing setup.",
    key_objections: 'Manual review required'
  };
}

// Pass through ALL context for the brief generation step
return { ...context, ...scoreData };

// ── STEP 7: Parse brief + build email draft template ─────────────────
const geminiResponse = $input.item.json;
const scoreData = $('Parse Score Response').item.json;
const d = scoreData;

// Parse brief text from AI
let briefText = '';
try {
  briefText = geminiResponse.choices[0].message.content || '';
} catch(e) {
  briefText = '# Pre-Call Brief\n\nBrief generation failed. Please review this lead manually.\n\n**Lead:** ' + d.fullName + '\n**Company:** ' + d.company + '\n**Challenge:** ' + d.challenge;
}

// ── Build email draft template ────────────────────────────────────────
const tier = d.tier;
const firstName = d.firstName;
const company = d.company;
const challenge = d.challenge || 'your current marketing challenges';

const urgencyLine = tier === 'Hot'
  ? 'Given the strong fit we can see, someone from our team will be in touch with you very shortly.'
  : 'Our team will review your application and be in touch within 2 business days.';

const challengeRef = challenge.length > 10
  ? 'Based on what you shared about your marketing challenge, you will find the Framework particularly relevant - especially the infrastructure and governance sections.'
  : 'You will find the Framework especially useful as a starting point for our conversation.';

const emailSubject = 'Your Live Marketing Strategy Session - ' + company;

const emailBody = 'Hi ' + firstName + ',\n\n'
  + 'Thank you for applying for a Live Marketing Strategy Session.\n\n'
  + challengeRef + '\n\n'
  + 'You can read our thinking on why the campaign cycle is over and what replaces it here: https://www.candidplatform.com\n\n'
  + urgencyLine + '\n\n'
  + 'Looking forward to the conversation.\n\n'
  + 'The Candid Team';

return {
  ...scoreData,
  brief_text:         briefText,
  brief_generated_at: new Date().toISOString(),
  email_subject:      emailSubject,
  email_body:         emailBody
};

// ── STEP 8: Build tier-specific Slack messages ───────────────────────
const d = $('Parse Brief + Draft Email').item.json;
const score = d.weighted_total;
const tier  = d.tier;

// ─── Score breakdown for brief ────────────────────────────────────────
const scoreBreakdown = `Seniority: ${d.score_seniority}/10 · Size: ${d.score_size}/10 · Industry: ${d.score_industry}/10 · Geography: ${d.score_geography}/10 · Signals: ${d.score_signals}/10`;

// ─── Hot Lead Message ─────────────────────────────────────────────────
const hotMessage = `🔥 *HOT LEAD — Score: ${score}/10*

*${d.fullName}* | ${d.role} | *${d.company}*
🏢 ${d.apollo_employees} employees · ${d.apollo_industry} · ${d.apollo_country}

💬 *Their challenge:* "${d.challenge}"

✅ *Product fit:* ${d.product_recommendation}
📞 *Open with:* ${d.opening_line}
⚠️ *Objections to prep:* ${d.key_objections}

📊 *Score breakdown:* ${scoreBreakdown}
💡 *Evidence:* ${d.evidence}

⚡ _High priority — follow up as soon as possible._`;

// ─── Warm Lead Message ────────────────────────────────────────────────
const warmMessage = `📋 *New Lead — Score: ${score}/10 (Warm)*

*${d.fullName}* | ${d.role} | *${d.company}*
🏢 ${d.apollo_employees} employees · ${d.apollo_industry} · ${d.apollo_country}

💬 *Their challenge:* "${d.challenge}"
✅ *Product fit:* ${d.product_recommendation}

📊 *Score breakdown:* ${scoreBreakdown}
💡 ${d.evidence}`;

// ─── Email Approval Message ───────────────────────────────────────────
const emailApprovalMessage = `✉️ *Email Approval Required*

*Lead:* ${d.fullName} from *${d.company}* (Score: ${score}/10 — ${tier})

*Proposed confirmation email:*
───────────────────────────
*Subject:* ${d.email_subject}

${d.email_body}
───────────────────────────

✅ React with :white_check_mark: to approve and send
✏️ Reply to this message to request changes

_If no action in 4 hours, this will escalate to the manager._
_Auto-reminder will fire at the 2-hour mark for Hot leads._`;

const shouldSendTeamAlert = tier === 'Hot' || tier === 'Warm';
const teamChannel = tier === 'Hot'
  ? 'C0B5ZPANA4T'
  : 'C0B70CSUJ0Y';

return {
  ...d,
  hot_message:            hotMessage,
  warm_message:           warmMessage,
  email_approval_message: emailApprovalMessage,
  should_send_team_alert: shouldSendTeamAlert,
  team_slack_channel:     teamChannel,
  team_slack_message:     tier === 'Hot' ? hotMessage : warmMessage
};

